# Module defining generic container types

from shapes import Shape, IDrawable, IMeasurable

class Box[T]:
    items: list[T]

    def __init__(self):
        self.items = []

    def add(self, item: T) -> None:
        self.items.append(item)

    def get_all(self) -> list[T]:
        return self.items.copy()

    def count(self) -> int:
        return len(self.items)

class ShapeContainer:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add_shape(self, shape: Shape) -> None:
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total += shape.calculate_area()
        return total

    def get_drawables(self) -> list[IDrawable]:
        result: list[IDrawable] = []
        for shape in self.shapes:
            # Check if shape implements IDrawable
            # Using a type-safe cast pattern
            result.append(shape as IDrawable)
        return result

