# Utility functions and helpers

def format_number(n: float, decimals: int) -> str:
    # Simple float formatting
    factor: float = 1.0
    for i in range(decimals):
        factor *= 10.0
    rounded: float = (n * factor + (0.5 if n >= 0 else -0.5)) // 1 / factor
    return f"{{rounded}}"

def clamp(value: float, min_val: float, max_val: float) -> float:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

enum Status:
    OK = 0
    WARNING = 1
    ERROR = 2

struct Dimension:
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    def aspect_ratio(self) -> float:
        if self.height == 0.0:
            return 0.0
        return self.width / self.height

def calculate_statistics(values: list[float]) -> tuple[float, float]:
    # Returns (sum, average)
    if len(values) == 0:
        return (0.0, 0.0)
    total: float = sum(values)
    avg: float = total / len(values)
    return (total, avg)
